   174→	s.logger = s.logger.New("org", orgId, "cfg", id)
   175→
   176→	s.logger.Info("Synchronizing config with external Alertmanager group")
   177→	if err := s.manager.ApplyConfig(notifierCfg, headers); err != nil {
   178→		return err
   179→	}
   180→
   181→	sdCfgs := make(map[string]discovery.Configs)
   182→	for k, v := range notifierCfg.AlertingConfig.AlertmanagerConfigs.ToMap() {
   183→		sdCfgs[k] = v.ServiceDiscoveryConfigs
   184→	}
   185→
   186→	return s.sdManager.ApplyConfig(sdCfgs)
   187→}
