   208→// SendAlerts sends a set of alerts to the configured Alertmanager(s).
   209→func (s *ExternalAlertmanager) SendAlerts(alerts apimodels.PostableAlerts) {
   210→	if len(alerts.PostableAlerts) == 0 {
   211→		return
   212→	}
   213→	as := make([]*Alert, 0, len(alerts.PostableAlerts))
   214→	for _, a := range alerts.PostableAlerts {
   215→		na := s.alertToNotifierAlert(a)
   216→		as = append(as, na)
   217→
   218→		s.logger.Debug(
   219→			"Sending alert",
   220→			"alert",
   221→			na.String(),
   222→			"starts_at",
   223→			na.StartsAt,
   224→			"ends_at",
   225→			na.EndsAt)
   226→	}
   227→
   228→	s.manager.Send(as...)
   229→}
