   232→func (s *ExternalAlertmanager) Stop() {
   233→	s.logger.Info("Shutting down communication with the external Alertmanager group")
   234→	s.sdCancel()
   235→	s.manager.Stop()
   236→	s.wg.Wait()
   237→}
